files./src/TicTacToe.js:
import React, { useState } from 'react';

const LINES = [
  [0, 1, 2], [3, 4, 5], [6, 7, 8],
  [0, 3, 6], [1, 4, 7], [2, 5, 8],
  [0, 4, 8], [2, 4, 6],
];

function getWinner(board) {
  for (const [a, b, c] of LINES) {
    if (board[a] && board[a] === board[b] && board[a] === board[c]) return board[a];
  }
  return null;
}

export default function TicTacToe() {
  const [board, setBoard] = useState(Array(9).fill(null));
  const [xNext, setXNext] = useState(true);

  const winner = getWinner(board);
  const draw = !winner && board.every(Boolean);
  const status = winner ? `${winner} wins!` : draw ? "It's a draw" : `${xNext ? 'X' : 'O'} to move`;

  const play = (i) => {
    if (board[i] || winner) return;
    const next = board.slice();
    next[i] = xNext ? 'X' : 'O';
    setBoard(next);
    setXNext(!xNext);
  };

  const reset = () => {
    setBoard(Array(9).fill(null));
    setXNext(true);
  };

  return (
    <div>
      <p style={{ fontWeight: 600, fontSize: 18 }}>{status}</p>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 72px)', gap: 6 }}>
        {board.map((cell, i) => (
          <button
            key={i}
            onClick={() => play(i)}
            style={{ width: 72, height: 72, fontSize: 32, fontWeight: 700, cursor: cell || winner ? 'default' : 'pointer', border: '1px solid #cbd5e1', borderRadius: 8, background: '#fff', color: cell === 'X' ? '#2563eb' : '#dc2626' }}
          >
            {cell}
          </button>
        ))}
      </div>
      <button onClick={reset} style={{ marginTop: 14, padding: '8px 16px', cursor: 'pointer' }}>Reset</button>
    </div>
  );
}

