import { Component } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-tic-tac-toe',
  template: `
    <div>
      <p style="font-weight: 600; font-size: 18px;">{{ status }}</p>
      <div style="display: grid; grid-template-columns: repeat(3, 72px); gap: 6px;">
        <button
          *ngFor="let cell of board; let i = index"
          (click)="play(i)"
          [style.color]="cell === 'X' ? '#2563eb' : '#dc2626'"
          [style.cursor]="cell || winner ? 'default' : 'pointer'"
          style="width: 72px; height: 72px; font-size: 32px; font-weight: 700; border: 1px solid #cbd5e1; border-radius: 8px; background: #fff;"
        >{{ cell }}</button>
      </div>
      <button (click)="reset()" style="margin-top: 14px; padding: 8px 16px; cursor: pointer;">Reset</button>
    </div>
  `,
})
export class TicTacToeComponent {
  board: (string | null)[] = Array(9).fill(null);
  xNext = true;
  lines = [
    [0, 1, 2], [3, 4, 5], [6, 7, 8],
    [0, 3, 6], [1, 4, 7], [2, 5, 8],
    [0, 4, 8], [2, 4, 6],
  ];

  get winner(): string | null {
    for (const [a, b, c] of this.lines) {
      if (this.board[a] && this.board[a] === this.board[b] && this.board[a] === this.board[c]) {
        return this.board[a];
      }
    }
    return null;
  }

  get status(): string {
    if (this.winner) {
      return this.winner + ' wins!';
    }
    if (this.board.every(Boolean)) {
      return "It's a draw";
    }
    return (this.xNext ? 'X' : 'O') + ' to move';
  }

  play(i: number): void {
    if (this.board[i] || this.winner) {
      return;
    }
    this.board[i] = this.xNext ? 'X' : 'O';
    this.xNext = !this.xNext;
  }

  reset(): void {
    this.board = Array(9).fill(null);
    this.xNext = true;
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Tic-Tac-Toe Demo</h1>
      <app-tic-tac-toe></app-tic-tac-toe>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, TicTacToeComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
